var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一件重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"經過長久的思考，你明白在今後即將面對的命運中，她是不可缺少的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你下定決心。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called her to your office. She said she'd be here soon.","TWN":"做好心理準備後，你將她傳喚到老闆辦公室，她說馬上就會過來。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"……옛날에 말이야. 내가 아주 어렸을 때.","JPN":"……昔さ、私がとても小さかった頃。","ENG":"...Long ago. When I was very young.","TWN":"……很久以前，在我還很小的時候，"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"엄마, 아빠를 따라 음악회를 자주 갔었거든?","JPN":"お母さんやお父さんに連れられて､よく音楽会に行ってたんだ。","ENG":"I used to go to concerts with my parents.","TWN":"常常跟著爸爸媽媽一起去聽音樂會喔！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"연주가 시작되고 악기가 하나 둘 소리를 얹을 때마다 볼이 엄청 간지러운 거야.","JPN":"演奏が始まって、楽器の音が一つ、また一つと重なるたびにどうしようもなく頬がくすぐったくってさ。","ENG":"When the performance began, and each of the instruments’ sounds started coming together, my cheeks would itch so much.","TWN":"演奏開始後，隨著一個接著一個的樂器聲揚起，我的臉頰總是特別癢。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"이제는 그게 전율이라는 걸 알지만, 그때는 어렸으니까. 무슨 영문인지 몰랐지.","JPN":"今ではそれが戦慄から来るものだってわかるけど、その時はまだ小さかったから。訳がわからなくて。","ENG":"Now I know that I was getting the chills, but back then I had no idea because I was young.","TWN":"後來我才知道，原來那是當你感到震撼時會有的反應，但我那時候還小，根本不知道是怎麼回事。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"그래도 음악회라고, 숨 죽여 웃으면서 볼을 마구 긁고 있으면 어떻게 알았는지 아빠가 내 손을 꼭 붙잡고, 엄마가 내 양 볼을 감싸 줬어.","JPN":"でも音楽会だからって声も出さずに笑いながら頬を掻いてると、なんでわかったんだろうね、お父さんは私の手をぎゅっと握ってくれて、お母さんは私の両頬を手で包んでくれた。","ENG":"I would keep quiet and scratch my cheeks, but somehow my dad would soon realize and clutch my hands while my mom caressed my cheeks.","TWN":"不知道爸爸媽媽是怎麼發現的，當我邊笑邊抓臉的時候，爸爸就會緊緊握住我的手，而媽媽會捧著我的臉。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"무척…… 따뜻한 손길이었어.","JPN":"とても……暖かい手だった。","ENG":"It was... a warm feeling.","TWN":"他們的手……真的非常溫暖。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"희미한 어린 시절의 기억이지만…… 이상하게 그 순간만큼은 진하게 남아 있네.","JPN":"子どもの頃のかすかな記憶だけど……不思議とその瞬間だけは鮮明に覚えてるんだ。","ENG":"It’s all just vague memories from my childhood... But I still remember those moments clearly.","TWN":"雖然是小時候模糊的記憶……但很奇怪，那個畫面我就是印象非常深刻！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"아아, 첩보원 치고 꽤나 감성적인 얘기지?","JPN":"ああ、諜報員にしてはずいぶんと感傷的な話でしょ？","ENG":"Ah, quite a sentimental story for a spy, isn’t it?","TWN":"哎呀～身為一個情報員，不該這講這麼內心的事對吧？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"이래봬도 음악가 집안이라고. 어렸을 때는 피아노도 곧잘 쳤어.","JPN":"これでも音楽家の家系だからね。子どもの頃はピアノもよく弾いてたよ。","ENG":"It may not look like it, but I’m from a family of musicians. I was pretty good at the piano when I was younger.","TWN":"你別看我這樣，我也是出身音樂世家呢！我小時候也彈過鋼琴喔！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"살면서 다시는 그런 손길 느낄 수 없을 거라고 생각했는데…….","JPN":"一生でもう二度とあの時のような暖かさを感じることはないと思ってたのに……","ENG":"I never thought I would be able to feel such a thing again...","TWN":"我原本以為，在我有生之年，應該很難再感受到手心傳來的溫暖……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"네가 가끔 내밀어 주던 손을 붙잡을 때마다 그때의 기억이 떠오르더라.","JPN":"君がたまに差し出してくれた手を掴むたびに、あの時の記憶が蘇ってきたよ。","ENG":"But whenever I hold the hand you reach out to me, it would remind me of those moments.","TWN":"但每當我握住你偶爾伸出的手時，那時的回憶就會湧現。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"내가 사는 지역에선 매일매일이 전쟁이고 고통이었는데, 그걸 잠깐이나마 잊을 만큼 따뜻했어.","JPN":"私が住んでいたところでは戦争と苦痛の毎日だったのに。それを一瞬だけでも忘れられるほど暖かかった。","ENG":"Where I’m from, there’s war and suffering going on everyday. But those moments were warm enough for me to forget about all the bad stuff. Even if for just that moment.","TWN":"我住的地方，每天都在發生戰爭跟痛苦的事，你手心的溫暖卻可以令我暫時遺忘這些事。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"나보고 힘내라고 했던가? 투박하지만 듣기 좋은 응원이었는데.","JPN":"頑張れって言ってくれたっけ。ありふれた言葉だけど、嬉しかったよ。","ENG":"Did you tell me to cheer up? A bit basic, but I liked it.","TWN":"你是叫我加油嗎？雖然有點笨拙，但聽起來滿開心的。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"하지만…… 뭔가를 하려고 하면 할수록 엉망진창이 되어 버리는 나에게도 그럴 자격이 있을까?","JPN":"でも……何かをしようとすればするほどダメになってしまう私にも、その資格があるのかな。","ENG":"It’s just... Whenever I attempt to do anything, I end up messing myself up. Do you think I have the right to cheer up?","TWN":"不過……當我想做些什麼時，通常都會把事情搞砸，我真的有資格那麼做嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"……그래. 너라면 그렇게 말해줄 줄 알았어. 괜찮다고, 나도 그럴 자격이 있다고.","JPN":"……うん、君ならそう言ってくれるってわかってた。大丈夫だと、私にもその資格があると。","ENG":"...Yeah. I knew you’d say that. That’s it’s all okay and that I have as much right as anybody.","TWN":"……我就知道你會這麼說！告訴我沒關係，我當然有資格。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};